class Solution(object):
    def findXSum(self, nums, k, x):
        from collections import Counter
        result = []
        for i in range(len(nums) - k + 1):
            sub = nums[i:i + k]
            cnt = Counter(sub)
            top = sorted(cnt.keys(), key=lambda v: (-cnt[v], -v))[:x]
            result.append(sum(v * cnt[v] for v in top))
        return result
